		WriteTimeout: 3 * time.Second,
	}

	statusCode, body, err := httpClient.Get(nil, req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
			"error":   "Failed to validate webhook URL",
			"details": err.Error(),
		})
	}

	// Check if the status code indicates success (e.g., 2xx)
	if statusCode < 200 || statusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":       "Webhook URL returned non-success status",
			"status_code": statusCode,
			"body":        string(body),
		})
	}

	// Save the configuration
	savedWebhookURL = req.WebhookURL

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"url":     savedWebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

