)

// ConfigureWebhook handles the webhook configuration request.
// It expects a JSON body with a "webhook_url" field, validates the URL,
// and returns the result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define the request structure
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	// Parse the JSON body
	var req Request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	// Validate that webhook_url is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := fiber.AcquireClient()
	defer fiber.ReleaseClient(client)

	// Send a test GET request to the webhook URL
	// We use the client's Get method. 
	// Note: fiber.Get creates a new request, client.Get executes it.
	agent := client.Get(req.WebhookURL)
	agent.Timeout(3 * time.Second)

	_, _, errs := agent.String()
	if len(errs) > 0 {
		log.Printf("Webhook validation failed for %s: %v", req.WebhookURL, errs)
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to validate webhook URL",
			"url":     req.WebhookURL,
		})
	}

	// If the request was successful (no network errors), save the configuration.
	// In a real application, you would save this to a database or config file here.
	// For this example, we will just log it.
	log.Printf("Webhook configured successfully for URL: %s", req.WebhookURL)

	// Return a success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

