package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhook handles the configuration of a webhook URL.
// It expects a JSON body with a "webhook_url" field.
// It validates the URL by sending a GET request with a 3-second timeout.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define the request payload structure
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req Request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"status":  "validation_failed",
			"message": "Failed to reach webhook URL",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook returned a success status code
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"status":  "validation_failed",
			"message": "Webhook URL returned an error status",
			"code":    resp.StatusCode,
		})
	}

	// Save the configuration (In a real application, this would be saved to a database)
	// For this example, we will just log it
	log.Printf("Webhook configured successfully: %s", req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured and validated successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

