package main

import (
	"log"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Config represents the application configuration
type Config struct {
	WebhookURL string `json:"webhook_url"`
}

// Global configuration variable
var appConfig Config

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var req Config
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	// Validate that webhook_url is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	// Note: We use fiber's built-in agent to perform the request
	agent := fiber.Get(req.WebhookURL)
	agent.Timeout(3 * time.Second)

	statusCode, body, errs := agent.String()

	// Check for errors during the request
	if len(errs) > 0 {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"error": "Failed to validate webhook URL",
			"details": errs[0].Error(),
		})
	}

	// Check if the webhook endpoint returned a successful status code
	if statusCode != fiber.StatusOK {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook URL validation failed",
			"status_code": statusCode,
			"body": string(body),
		})
	}

	// Save the configuration
	appConfig.WebhookURL = req.WebhookURL

	// Return success response
	return ctx.JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"webhook_url": appConfig.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

