		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Security Fix: Prevent Server-Side Request Forgery (SSRF)
	// Block requests to private/internal IP addresses to prevent unauthorized access to local resources.
	host := parsedURL.Hostname()
	if isPrivateIP(host) {
