import (
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhook handles the webhook configuration request.
// It expects a JSON body with a "webhook_url" field.
// It validates the URL by sending a GET request with a 3-second timeout,
// then saves the configuration and returns the result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define the request payload structure
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	// Parse the JSON body
	var req Request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	// Validate that webhook_url is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := fiber.AcquireClient()
	defer fiber.ReleaseClient(client)

	// Send a test GET request to the webhook URL
	// We use a generic User-Agent to avoid being blocked by default server rules
	reqAgent := client.Get(req.WebhookURL).
		Timeout(3 * time.Second).
		Set("User-Agent", "Fiber-Webhook-Validator/1.0")

	code, body, errs := reqAgent.String()
	if len(errs) > 0 {
		// If there are network errors or timeout, the webhook is considered invalid
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"error":   "Failed to validate webhook URL",
			"details": errs[0].Error(),
		})
	}

	// Check if the status code indicates success (2xx)
	if code < 200 || code >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"error": "Webhook URL returned non-success status",
			"code":  code,
			"body":  body,
		})
	}

	// If validation passes, save the configuration.
	// In a real application, this would involve saving to a database or config file.
	// For this snippet, we simulate the save operation.
	// saveConfiguration(req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"url":     req.WebhookURL,
	})
}

