package main

import (
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhook handles the POST request to configure a webhook URL.
// It validates the URL by sending a GET request with a 3-second timeout,
// then saves the configuration and returns the result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define a struct to parse the incoming JSON body
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req Request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid JSON body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	// fiber.AcquireClient is used to get a client from the pool.
	// The timeout is set on the request agent, not the client struct directly in v2.
	client := fiber.AcquireClient()
	defer fiber.ReleaseClient(client)

	// Send a test GET request to the webhook URL
	// We use the client's Get method which creates a new Agent and performs the request.
	// The Agent follows redirects by default.
	agent := client.Get(req.WebhookURL)
	agent.Timeout(3 * time.Second)

	statusCode, _, errs := agent.String()
	if len(errs) > 0 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL",
			"error":   errs[0].Error(),
		})
	}

	// Check if the status code indicates success (e.g., 2xx)
	if statusCode < 200 || statusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned non-success status",
			"status":  statusCode,
		})
	}

	// Save the configuration (In a real application, this would be saved to a database)
	// For this example, we simulate saving by printing or storing in memory
	// fmt.Printf("Configuration saved for URL: %s\n", req.WebhookURL)

	// Return a success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"data": fiber.Map{
			"webhook_url": req.WebhookURL,
		},
	})
}

