package main

import (
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhook handles the webhook configuration request.
// It expects a JSON body with a "webhook_url" field, validates the URL,
// and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define the request body structure
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req Request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := fiber.AcquireClient()
	defer fiber.ReleaseClient(client)

	// Send a test GET request to the webhook URL
	// Timeout is set on the request agent, not the client directly
	agent := client.Get(req.WebhookURL)
	agent.Timeout(3 * time.Second)
	statusCode, _, bodyErrors := agent.String()

	// Check for connection or DNS errors during the request attempt
	if len(bodyErrors) > 0 {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
			"error":   "Webhook validation failed",
			"details": bodyErrors[0].Error(),
		})
	}

	// Check if the webhook returned a successful status code
	if statusCode != fiber.StatusOK {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook URL returned non-200 status",
			"code":  statusCode,
		})
	}

	// In a real application, you would save the configuration to a database here.
	// For this example, we assume the save is successful.

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

