// Config struct to hold the webhook configuration
type Config struct {
	WebhookURL string `json:"webhook_url"`
}

// Response struct to send back the result
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	URL     string `json:"url,omitempty"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var config Config
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate that webhook_url is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Create a new HTTP client with a 3-second timeout
	client := fiber.AcquireClient()
	defer fiber.ReleaseClient(client)

	// Send a test GET request to the webhook URL
	agent := client.Get(config.WebhookURL)
	agent.Timeout(3 * time.Second)

	statusCode, body, errs := agent.String()
	if len(errs) > 0 {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: request error",
		})
	}

	// Check if the status code indicates success (e.g., 2xx)
	if statusCode < 200 || statusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "Webhook URL validation failed: server returned non-success status",
		})
	}

	// Save the configuration (In a real application, you would save this to a database)
	// For this example, we will just log it
	log.Printf("Configuration saved for Webhook URL: %s. Response: %s", config.WebhookURL, body)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     config.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

