		return ctx.JSON(Response{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Basic validation to ensure the URL is not empty
	if req.WebhookURL == "" {
		ctx.Status(fiber.StatusBadRequest)
		return ctx.JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create an HTTP client
	client := fiber.AcquireClient()
	defer fiber.ReleaseClient(client)

	// Send a test GET request to the webhook URL
	// We use a generic User-Agent to avoid being blocked by default server configurations
	reqAgent := client.Get(req.WebhookURL)
	reqAgent.Timeout(3 * time.Second)
	reqAgent.Set("User-Agent", "FiberWebhookValidator/1.0")

	statusCode, body, errs := reqAgent.String()

	// Check for errors during the request (e.g., DNS failure, connection refused, timeout)
	if len(errs) > 0 {
		log.Printf("Webhook validation failed for URL %s: %v", req.WebhookURL, errs)
		ctx.Status(fiber.StatusBadGateway)
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to reach webhook URL",
		})
	}

	// Check if the webhook server returned a successful status code (2xx)
	if statusCode >= 200 && statusCode < 300 {
		// In a real application, you would save the configuration (req.WebhookURL) to a database here.
		// For this example, we assume the save operation is successful.
		log.Printf("Webhook validated successfully for URL: %s. Response: %s", req.WebhookURL, body)

		return ctx.JSON(Response{
			Success: true,
			Message: "Webhook configured successfully",
		})
	}

	// The URL was reachable, but returned an error status code
	log.Printf("Webhook URL returned non-2xx status: %d", statusCode)
	ctx.Status(fiber.StatusBadGateway)
	return ctx.JSON(Response{
		Success: false,
		Message: "Webhook URL returned an error",
	})
}

