package main

import (
	"log"
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhook handles the POST request to configure a webhook URL.
// It validates the URL by sending a GET request with a 3-second timeout.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define the request body structure
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req Request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client
	client := fiber.AcquireClient()
	defer fiber.ReleaseClient(client)

	// Validate the webhook URL by sending a GET request
	// Using User-Agent to identify the request
	agent := client.Get(req.WebhookURL).
		Timeout(3 * time.Second).
		Set("User-Agent", "WebhookValidator/1.0")

	code, body, errs := agent.String()
	if errs != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"error":   "Failed to validate webhook URL",
			"details": errs,
		})
	}

	// Check if the status code indicates success (2xx)
	if code < 200 || code >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"error": "Webhook URL returned non-success status",
			"code":  code,
			"body":  body,
		})
	}

	// Save the configuration (In-memory simulation)
	// In a real application, you would save this to a database or config file.
	log.Printf("Configuration saved: WebhookURL=%s", req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

